import React, { useEffect, useState, useCallback } from 'react';
import api from '../api';
import { useAuth } from '../context/AuthContext';

const CATEGORIES = ['crane','excavator','generator','compressor','mixer','bulldozer','forklift','other'];
const EMOJIS = { crane:'🏗️', excavator:'⛏️', generator:'⚡', compressor:'🔩', mixer:'🚧', bulldozer:'🚜', forklift:'🏭', other:'⚙️' };

function EquipmentModal({ equip, onClose, onSaved }) {
  const [form, setForm] = useState(equip || { name: '', category: 'crane', dailyRate: '', description: '', location: 'Warangal Depot', emoji: '🏗️' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const isEdit = !!equip?.id;

  const handleChange = e => {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value, ...(name === 'category' ? { emoji: EMOJIS[value] || '⚙️' } : {}) }));
  };

  const handleSubmit = async e => {
    e.preventDefault(); setError(''); setLoading(true);
    try {
      if (isEdit) await api.put(`/equipment/${equip.id}`, form);
      else await api.post('/equipment', form);
      onSaved();
    } catch (err) { setError(err.response?.data?.error || 'Failed to save.'); }
    finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <h2 className="modal-title">{isEdit ? 'EDIT EQUIPMENT' : 'ADD EQUIPMENT'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="grid-2" style={{ gap: 12 }}>
            <div className="form-group" style={{ gridColumn: '1/-1' }}>
              <label>Equipment Name *</label>
              <input name="name" className="form-control" value={form.name} onChange={handleChange} required placeholder="e.g. Tower Crane CR-15" />
            </div>
            <div className="form-group">
              <label>Category *</label>
              <select name="category" className="form-control" value={form.category} onChange={handleChange}>
                {CATEGORIES.map(c => <option key={c} value={c}>{EMOJIS[c]} {c.charAt(0).toUpperCase() + c.slice(1)}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>Daily Rate (₹) *</label>
              <input name="dailyRate" type="number" className="form-control" value={form.dailyRate} onChange={handleChange} required min="1" placeholder="5000" />
            </div>
            <div className="form-group" style={{ gridColumn: '1/-1' }}>
              <label>Description</label>
              <textarea name="description" className="form-control" value={form.description} onChange={handleChange} placeholder="Specifications, capacity, model..." />
            </div>
            <div className="form-group">
              <label>Location</label>
              <input name="location" className="form-control" value={form.location} onChange={handleChange} />
            </div>
            {isEdit && (
              <div className="form-group">
                <label>Status</label>
                <select name="status" className="form-control" value={form.status} onChange={handleChange}>
                  {['available','maintenance','retired'].map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            )}
          </div>
          {error && <div className="auth-error">⚠ {error}</div>}
          <div className="modal-footer">
            <button type="button" className="btn btn-ghost" onClick={onClose}>Cancel</button>
            <button type="submit" className="btn btn-primary" disabled={loading}>
              {loading ? <span className="spinner" style={{ width: 16, height: 16, borderWidth: 2 }} /> : isEdit ? 'Save Changes' : 'Add Equipment'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default function EquipmentPage() {
  const { isAdminOrManager, isAdmin } = useAuth();
  const [equipment, setEquipment] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [modal, setModal] = useState(null); // null | 'add' | equipObj
  const [deleting, setDeleting] = useState(null);

  const fetchEquipment = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (search) params.append('search', search);
      if (statusFilter) params.append('status', statusFilter);
      if (categoryFilter) params.append('category', categoryFilter);
      const res = await api.get(`/equipment?${params}`);
      setEquipment(res.data.data);
      setTotal(res.data.total);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  }, [search, statusFilter, categoryFilter]);

  useEffect(() => { fetchEquipment(); }, [fetchEquipment]);

  const handleDelete = async (id) => {
    if (!window.confirm('Retire this equipment?')) return;
    setDeleting(id);
    try { await api.delete(`/equipment/${id}`); fetchEquipment(); }
    catch (e) { alert(e.response?.data?.error || 'Failed'); }
    finally { setDeleting(null); }
  };

  return (
    <div className="fade-in">
      <div className="page-header">
        <div>
          <h1 className="page-title">EQUIPMENT CATALOG</h1>
          <div className="page-sub">{total} items in fleet</div>
        </div>
        {isAdminOrManager() && (
          <button className="btn btn-primary" onClick={() => setModal('add')}>+ Add Equipment</button>
        )}
      </div>

      {/* Filters */}
      <div className="filter-bar">
        <div className="search-wrap" style={{ flex: 1 }}>
          <span className="search-icon">🔍</span>
          <input className="form-control search-input" placeholder="Search equipment..." value={search}
            onChange={e => setSearch(e.target.value)} />
        </div>
        <select className="form-control" style={{ width: 140 }} value={statusFilter} onChange={e => setStatusFilter(e.target.value)}>
          <option value="">All Status</option>
          {['available','rented','maintenance','retired'].map(s => <option key={s} value={s}>{s}</option>)}
        </select>
        <select className="form-control" style={{ width: 150 }} value={categoryFilter} onChange={e => setCategoryFilter(e.target.value)}>
          <option value="">All Categories</option>
          {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>

      {loading ? (
        <div className="loading-wrapper"><div className="spinner" /></div>
      ) : equipment.length === 0 ? (
        <div className="empty-state"><div className="icon">🏗️</div><p>No equipment found</p></div>
      ) : (
        <div className="grid-3">
          {equipment.map(eq => (
            <div key={eq.id} className="panel" style={{ cursor: 'default', transition: 'border-color .2s' }}
              onMouseEnter={e => e.currentTarget.style.borderColor = 'var(--accent)'}
              onMouseLeave={e => e.currentTarget.style.borderColor = 'var(--border)'}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: 90, background: 'var(--bg)', fontSize: 52, borderBottom: '1px solid var(--border)' }}>
                {eq.emoji}
              </div>
              <div className="panel-body" style={{ padding: '14px 16px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
                  <span className={`badge badge-${eq.status}`}>● {eq.status}</span>
                  <span className="mono" style={{ fontSize: 10, color: 'var(--muted)' }}>{eq.equipmentId}</span>
                </div>
                <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 3 }}>{eq.name}</div>
                <div style={{ fontSize: 12, color: 'var(--muted)', marginBottom: 10, fontFamily: 'DM Mono, monospace' }}>
                  {eq.category} · {eq.location}
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div style={{ fontFamily: 'Bebas Neue, cursive', fontSize: 22, color: 'var(--accent)' }}>
                    ₹{Number(eq.dailyRate).toLocaleString('en-IN')}
                    <span style={{ fontFamily: 'Barlow, sans-serif', fontSize: 11, color: 'var(--muted)' }}>/day</span>
                  </div>
                  {isAdminOrManager() && (
                    <div style={{ display: 'flex', gap: 6 }}>
                      <button className="btn btn-ghost btn-sm" onClick={() => setModal(eq)}>Edit</button>
                      {isAdmin() && (
                        <button className="btn btn-danger btn-sm" onClick={() => handleDelete(eq.id)}
                          disabled={deleting === eq.id}>
                          {deleting === eq.id ? '...' : 'Retire'}
                        </button>
                      )}
                    </div>
                  )}
                </div>
                <div style={{ marginTop: 8, fontSize: 11, color: 'var(--muted)', fontFamily: 'DM Mono, monospace' }}>
                  {eq.totalRentals} rentals · ₹{Number(eq.totalRevenue).toLocaleString('en-IN')} earned
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {modal && (
        <EquipmentModal
          equip={modal === 'add' ? null : modal}
          onClose={() => setModal(null)}
          onSaved={() => { setModal(null); fetchEquipment(); }}
        />
      )}
    </div>
  );
}
